const n="/api/vehiculos";async function c(r){const o=new URLSearchParams;Object.entries(r).forEach(([a,t])=>{t!==void 0&&t!==""&&o.append(a,String(t))});const e=await fetch(`${n}?${o.toString()}`);if(!e.ok)throw new Error("Error al obtener vehículos");return e.json()}async function s(r){const o=await fetch(`${n}/${r}`);if(!o.ok)throw new Error("Vehículo no encontrado");return o.json()}async function i(r){const o=await fetch(n,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(r)});if(!o.ok)throw new Error("Error al crear vehículo");return o.json()}async function h(r,o){const e=await fetch(`${n}/${r}`,{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify(o)});if(!e.ok)throw new Error("Error al actualizar vehículo");return e.json()}export{s as a,i as c,c as g,h as u};
